import React, { useState } from 'react';

const Player: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false);

  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center">
          <img src="https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400" alt="Album Art" className="w-16 h-16 rounded-xl mr-4" />
          <div>
            <h2 className="text-xl font-bold">Song Title</h2>
            <p className="text-gray-600">Artist Name</p>
          </div>
        </div>
        <button onClick={togglePlay} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">
          {isPlaying ? 'Pause' : 'Play'}
        </button>
      </div>
    </div>
  );
};

export default Player;
